    "completeness_score": 0.00,
    "embodiment_coverage_score": 0.00,
    "overall_score": 0.00,
    "issues": [
      {
        "severity": "critical",
        "location": "说明书",
        "description": "提交审查的文件中完全缺少说明书内容，无法评估公开充分性、完整性和实施例覆盖度",
        "suggestion": "必须提供完整的说明书，包括：(1)技术领域；(2)背景技术（引用CBAM、SENet等现有注意力机制文献）；(3)发明内容（技术问题、技术方案、有益效果）；(4)附图说明；(5)具体实施方式（至少包含2-3个实施例，涵盖不同应用场景，并提供对比实验数据证明技术效果）"
